public interface ICommand {
  void Execute();
}

public class Light {
  public bool IsOn { get; private set; }
  public void TurnOn() => IsOn = true;
}

public class TurnOnLightCommand : ICommand {
  private readonly Light _light;
  public TurnOnLightCommand(Light light) { _light = light; }
  public void Execute() => _light.TurnOn();
}

public class RemoteControl {
  public void Press(ICommand command) => command.Execute();
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Invoker_ExecutesCommand() {
  var light = new Light();
  var command = new TurnOnLightCommand(light);
  var remote = new RemoteControl();

  remote.Press(command);

  Assert.IsTrue(light.IsOn);
}

[TestMethod]
public void Command_EncapsulatesReceiverCall() {
  var light = new Light();
  ICommand command = new TurnOnLightCommand(light);
  command.Execute();
  Assert.IsTrue(light.IsOn);
}
